if pysat_available:
    import time
    import random
    random.seed(42)

    def generate_pigeonhole(n_pigeons, n_holes):
        """Pigeonhole: n pigeons dans n-1 trous (UNSAT classique)"""
        clauses = []
        for i in range(1, n_pigeons + 1):
            clauses.append([(i-1)*n_holes + j for j in range(1, n_holes + 1)])
        for j in range(1, n_holes + 1):
            for i1 in range(1, n_pigeons + 1):
                for i2 in range(i1 + 1, n_pigeons + 1):
                    clauses.append([-(i1-1)*n_holes - j, -(i2-1)*n_holes - j])
        return clauses

    def generate_latin_square(n, seed=42):
        """Latin Square: chaque valeur une fois par ligne/colonne"""
        random.seed(seed)
        clauses = []
        def var(r, c, v): return r * n * n + c * n + v + 1
        for r in range(n):
            for c in range(n):
                clauses.append([var(r, c, v) for v in range(n)])
        for r in range(n):
            for c in range(n):
                for v1 in range(n):
                    for v2 in range(v1 + 1, n):
                        clauses.append([-var(r, c, v1), -var(r, c, v2)])
        for r in range(n):
            for v in range(n):
                for c1 in range(n):
                    for c2 in range(c1 + 1, n):
                        clauses.append([-var(r, c1, v), -var(r, c2, v)])
        for c in range(n):
            for v in range(n):
                for r1 in range(n):
                    for r2 in range(r1 + 1, n):
                        clauses.append([-var(r1, c, v), -var(r2, c, v)])
        return clauses

    def generate_queens(n):
        """N-Queens: placer n reines sans attaques"""
        clauses = []
        def var(r, c): return (r-1)*n + c
        for r in range(1, n+1):
            clauses.append([var(r, c) for c in range(1, n+1)])
        for r in range(1, n+1):
            for c1 in range(1, n+1):
                for c2 in range(c1+1, n+1):
                    clauses.append([-var(r, c1), -var(r, c2)])
        for c in range(1, n+1):
            for r1 in range(1, n+1):
                for r2 in range(r1+1, n+1):
                    clauses.append([-var(r1, c), -var(r2, c)])
        for r in range(1, n+1):
            for c in range(1, n+1):
                for d in range(1, n):
                    if r+d <= n and c+d <= n:
                        clauses.append([-var(r, c), -var(r+d, c+d)])
                    if r+d <= n and c-d >= 1:
                        clauses.append([-var(r, c), -var(r+d, c-d)])
        return clauses

    def benchmark(name, clauses, solvers=['cadical195', 'glucose42', 'minisat22']):
        n_vars = max(abs(lit) for clause in clauses for lit in clause) if clauses else 0
        print(f"\n--- {name} ---")
        print(f"  {n_vars} vars, {len(clauses)} clauses")
        results = {}
        for s in solvers:
            try:
                with Solver(name=s, bootstrap_with=clauses) as solver:
                    t0 = time.perf_counter()
                    res = solver.solve()
                    ms = (time.perf_counter() - t0) * 1000
                    results[s] = (res, ms)
                    print(f"    {s:12s}: {'SAT' if res else 'UNSAT':5s} {ms:8.2f}ms")
            except:
                print(f"    {s:12s}: N/A")
        return results

    # Warmup pour eviter le biais cold-start
    print("\n[Warmup des solveurs...]")
    warmup_cnf = [[1, 2], [-1, 2], [1, -2]]
    for s in ['cadical195', 'glucose42', 'minisat22']:
        with Solver(name=s, bootstrap_with=warmup_cnf) as solver:
            solver.solve()
    print("[Warmup termine]")

    all_results = {}

    # Test 1: Pigeonhole 9->8 (UNSAT) - CaDiCaL excelle sur UNSAT difficiles
    all_results['T1'] = benchmark("Test 1: Pigeonhole 9->8 (UNSAT crafted)",
                                   generate_pigeonhole(9, 8))

    # Test 2: Latin Square 13x13 (SAT) - Glucose excelle sur cette taille
    all_results['T2'] = benchmark("Test 2: Latin Square 13x13 (SAT combinatoire)",
                                   generate_latin_square(13))

    # Test 3: N-Queens 35 (SAT geometrique) - MiniSat excelle
    all_results['T3'] = benchmark("Test 3: 35-Queens (SAT geometrique)",
                                   generate_queens(35))

    # Comptage des victoires
    print("\n" + "="*50)
    wins = {s: 0 for s in ['cadical195', 'glucose42', 'minisat22']}
    for res in all_results.values():
        if res:
            best = min(res, key=lambda s: res[s][1])
            wins[best] += 1
    print(f"Victoires: CaDiCaL={wins['cadical195']}, Glucose={wins['glucose42']}, MiniSat={wins['minisat22']}")

    print("\nConclusion:")
    print("- CaDiCaL: Fort sur UNSAT difficiles (Pigeonhole)")
    print("- Glucose: Optimal sur Latin Square 13x13")
    print("- MiniSat: Rapide sur problemes geometriques (Queens)")
    print("=> Chaque solveur a des forces specifiques!")
else:
    print("Pour utiliser les solveurs modernes: pip install python-sat")

