if jvm_ready:
    from org.tweetyproject.logics.pl.syntax import Proposition, PlBeliefSet, Negation, Conjunction, Disjunction
    from org.tweetyproject.logics.pl.sat import Sat4jSolver, SatSolver
    from java.util import ArrayList
    from org.tweetyproject.logics.pl.reasoner import SatReasoner

    parser = PlParser()
    p = parser.parseFormula  

    kb = PlBeliefSet()

    for c in ("maths", "info", "phys"):
        kb.add(p(f"{c}_am || {c}_pm"))
        kb.add(Negation(p(f"{c}_am && {c}_pm")))

    kb.add(p("!(maths_am && phys_am)"))
    kb.add(p("!(maths_pm && phys_pm)"))

    kb.add(p("info_am"))

    SatSolver.setDefaultSolver(Sat4jSolver())
    solver = SatSolver.getDefaultSolver()

    witness = solver.getWitness(ArrayList(kb))
    if witness is None:
        print("Pas de solution.")
    else:
        vrais = {str(f) for f in witness}
        for nom, am in (("Maths", "maths_am"), ("Info", "info_am"), ("Physique", "phys_am")):
            if am in vrais:
                print(f"{nom:10} → matin")
            else:
                print(f"{nom:10} → après-midi")
    kb.add(p("phys_am"))
    if solver.isSatisfiable(ArrayList(kb)):
        print("\nPhysique le matin aussi → OK")
    else:   
        print("\nPhysique le matin aussi → contradiction")
else:
    print("Exemple saute : JVM Tweety non disponible")

