def _download(url, dest):
    try:
        urllib.request.urlretrieve(url, dest)
        return True
    except Exception as e:
        print(f"  ERREUR {dest.name}: {e}")
        return False

_to_download = []
for local_name, artifact in _MODULES.items():
    jar = LIB_DIR / f"{local_name}-{TWEETY_VERSION}.jar"
    if not jar.exists():
        url = f"{_BASE_URL}org.tweetyproject.{artifact}-{TWEETY_VERSION}.jar"
        _to_download.append((url, jar))
for name, url in _DEPS.items():
    jar = LIB_DIR / name
    if not jar.exists():
        _to_download.append((url, jar))

if _to_download:
    print(f"Telechargement de {len(_to_download)} JAR(s) Tweety {TWEETY_VERSION}...")
    ok = sum(_download(url, dest) for url, dest in _to_download)
    print(f"  {ok}/{len(_to_download)} JAR(s) telecharges dans {LIB_DIR}/.")
else:
