# --- 3.4.3 Resolution MaxSAT avec RC2 ---
if maxsat_imports_ok:
    # Detecter le script maxsat_solver.py
    maxsat_paths = [
        pathlib.Path("../ext_tools/maxsat_solver.py"),
        pathlib.Path("ext_tools/maxsat_solver.py"),
    ]

    maxsat_script = None
    for mp in maxsat_paths:
        if mp.exists():
            maxsat_script = mp.resolve()
            break

    if maxsat_script:
        print(f"MaxSAT script: {maxsat_script}")

        try:
            import sys
            import pysat
            print(f"PySAT version: {pysat.__version__}")

            # Creer fichier WCNF temporaire
            with tempfile.NamedTemporaryFile(mode='w', suffix='.wcnf', delete=False) as wcnf_file:
                wcnf_path = pathlib.Path(wcnf_file.name)
                top_weight = 1000

                wcnf_file.write(f"p wcnf 6 7 {top_weight}\n")
                # Clauses dures
                wcnf_file.write(f"{top_weight} -1 0\n")      # !a
                wcnf_file.write(f"{top_weight} 2 0\n")       # b
                wcnf_file.write(f"{top_weight} 2 3 0\n")     # b || c
                wcnf_file.write(f"{top_weight} 3 4 0\n")     # c || d
                wcnf_file.write(f"{top_weight} 5 3 6 0\n")   # f || c || g
                # Clauses molles
                wcnf_file.write("25 1 -2 0\n")              # a || !b, poids 25
                wcnf_file.write("15 -3 0\n")                # !c, poids 15

            # Executer le solveur
            result = subprocess.run(
                [sys.executable, str(maxsat_script), str(wcnf_path)],
                capture_output=True, text=True, timeout=10
            )

            if result.returncode == 0:
                print("\nResultats MaxSAT:")
                var_map = {1: 'a', 2: 'b', 3: 'c', 4: 'd', 5: 'f', 6: 'g'}
                for line in result.stdout.strip().split('\n'):
                    if line.startswith("s "):
                        print(f"  Status: {line[2:]}")
                    elif line.startswith("o "):
                        print(f"  Cout optimal: {line[2:]}")
                    elif line.startswith("v "):
                        lits = [int(x) for x in line[2:].split() if x != '0']
                        assignment = [f"{var_map[abs(l)]}={l>0}" for l in lits if abs(l) in var_map]
                        print(f"  Assignation: {', '.join(assignment)}")
            else:
                if "pysat.examples" in result.stderr or "No module named 'pysat'" in result.stderr:
                    print("ATTENTION: python-sat (pysat.examples.rc2) introuvable dans ce kernel.")
                    print("Cause: package satellite-science 'pysat' qui masque 'python-sat',")
                    print("ou kernel actif != 'epita_symbolic_ai'. Selectionnez le kernel 'epita_symbolic_ai'.")
                else:
                    print(f"Erreur: {result.stderr}")

            wcnf_path.unlink(missing_ok=True)

        except ImportError:
            print("PySAT non disponible")
    else:
        print("Script maxsat_solver.py non trouve")
else:
    print("Imports MaxSAT non disponibles.")

using System.IO;

string ikvmVer = "8.15.0", ikvmRid = "win-x64";
string nugetRoot = Environment.GetEnvironmentVariable("NUGET_PACKAGES")
    ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget", "packages");
string ikvmBaseAny = Path.Combine(nugetRoot, "ikvm.image", ikvmVer, "ikvm", "any", "any");
string ikvmArchDir = Path.Combine(nugetRoot, "ikvm.image.runtime." + ikvmRid, ikvmVer, "ikvm", "any", ikvmRid);
string ikvmHome    = Path.Combine(Path.GetTempPath(), "ikvm-home-" + ikvmVer + "-" + ikvmRid);

void IkvmCopyMerge(string src, string dst)
{
    foreach (var d in Directory.GetDirectories(src, "*", SearchOption.AllDirectories))
        Directory.CreateDirectory(d.Replace(src, dst));
    foreach (var f in Directory.GetFiles(src, "*", SearchOption.AllDirectories))
    {
        var t = f.Replace(src, dst);
        Directory.CreateDirectory(Path.GetDirectoryName(t));
        File.Copy(f, t, overwrite: true);
    }
}

if (Directory.Exists(ikvmBaseAny) && Directory.Exists(ikvmArchDir))
{
    Directory.CreateDirectory(ikvmHome);
    IkvmCopyMerge(ikvmBaseAny, ikvmHome);
    IkvmCopyMerge(ikvmArchDir, ikvmHome);
}
