else:
    print("JVM prete. Demonstration des regles de vote...")

    # Simulation Python des règles de base (indépendant de Tweety)
    print("\n--- Simulation Python des Regles de Vote ---")

    # Données: préférences de 5 votants sur 4 candidats
    candidates = ['A', 'B', 'C', 'D']

    # Chaque liste représente le classement d'un votant (du meilleur au pire)
    preferences = [
        ['A', 'B', 'C', 'D'],  # Votant 1
        ['A', 'C', 'B', 'D'],  # Votant 2
        ['B', 'C', 'D', 'A'],  # Votant 3
        ['C', 'B', 'D', 'A'],  # Votant 4
        ['D', 'C', 'B', 'A'],  # Votant 5
    ]

    print(f"Candidats: {candidates}")
    print(f"Nombre de votants: {len(preferences)}")
    print("\nPreferences individuelles:")
    for i, pref in enumerate(preferences, 1):
        print(f"  Votant {i}: {' > '.join(pref)}")

    # Règle de Borda
    print("\n--- Regle de Borda ---")
    borda_scores = {c: 0 for c in candidates}
    n = len(candidates)
    for pref in preferences:
        for rank, candidate in enumerate(pref):
            borda_scores[candidate] += (n - 1 - rank)  # n-1 points pour le 1er, 0 pour le dernier

    print("Scores Borda (points):")
    for c, score in sorted(borda_scores.items(), key=lambda x: -x[1]):
        print(f"  {c}: {score} points")
    borda_winner = max(borda_scores, key=borda_scores.get)
    print(f"Gagnant Borda: {borda_winner}")

    # Méthode de Condorcet
    print("\n--- Methode de Condorcet ---")

    # Compter les victoires en duels
    def pairwise_comparison(c1, c2, preferences):
        """Compte combien de votants préfèrent c1 à c2"""
        count = 0
        for pref in preferences:
            if pref.index(c1) < pref.index(c2):
                count += 1
        return count

    condorcet_matrix = {}
    for c1 in candidates:
        condorcet_matrix[c1] = {}
        for c2 in candidates:
            if c1 != c2:
                condorcet_matrix[c1][c2] = pairwise_comparison(c1, c2, preferences)

    print("Matrice des duels (lignes battent colonnes):")
    print("     " + "  ".join(candidates))
    for c1 in candidates:
        row = [str(condorcet_matrix[c1].get(c2, '-')).center(2) for c2 in candidates]
        print(f"  {c1}  {' '.join(row)}")

    # Chercher le gagnant de Condorcet
    condorcet_winner = None
    for c in candidates:
        wins_all = all(condorcet_matrix[c].get(other, 0) > len(preferences)//2 
                       for other in candidates if other != c)
        if wins_all:
            condorcet_winner = c
            break

    if condorcet_winner:
        print(f"Gagnant de Condorcet: {condorcet_winner} (bat tous les autres en duel)")
    else:
        print("Pas de gagnant de Condorcet (cycle de Condorcet probable)")

    # Règle de Copeland
    print("\n--- Regle de Copeland ---")
    copeland_scores = {c: 0 for c in candidates}
    for c1 in candidates:
        for c2 in candidates:
            if c1 != c2:
                if condorcet_matrix[c1][c2] > condorcet_matrix[c2][c1]:
                    copeland_scores[c1] += 1
                elif condorcet_matrix[c1][c2] < condorcet_matrix[c2][c1]:
                    copeland_scores[c1] -= 1

    print("Scores Copeland (victoires - defaites):")
    for c, score in sorted(copeland_scores.items(), key=lambda x: -x[1]):
        print(f"  {c}: {score:+d}")
    copeland_winner = max(copeland_scores, key=copeland_scores.get)
    print(f"Gagnant Copeland: {copeland_winner}")

projets = ['Projet_A', 'Projet_B', 'Projet_C', 'Projet_D']

preferences_jury = [
    ['Projet_A', 'Projet_B', 'Projet_C', 'Projet_D'],  # Membre 1: expert technique
    ['Projet_B', 'Projet_C', 'Projet_D', 'Projet_A'],  # Membre 2: expert financier
    ['Projet_C', 'Projet_D', 'Projet_A', 'Projet_B'],  # Membre 3: representant utilisateur
    ['Projet_D', 'Projet_A', 'Projet_B', 'Projet_C'],  # Membre 4: responsable environnemental
    ['Projet_A', 'Projet_C', 'Projet_B', 'Projet_D'],  # Membre 5: president du jury
]

def borda_score(preferences, candidats):
    """Calcule les scores Borda pour chaque candidat."""
    scores = {c: 0 for c in candidats}
    n = len(candidats)
    for pref in preferences:
        for rank, candidate in enumerate(pref):
            scores[candidate] += (n - 1 - rank)
    return scores

def condorcet_matrix(preferences, candidats):
    """Cree la matrice des duels par paires."""
    matrix = {c1: {c2: 0 for c2 in candidats if c2 != c1} for c1 in candidats}
    for pref in preferences:
        for i, c1 in enumerate(pref):
            for c2 in pref[i + 1:]:
                matrix[c1][c2] += 1
    return matrix

def detect_cycle(matrix):
    """Detecte s'il existe un cycle dans les preferences collectives."""
    candidats = list(matrix.keys())
    edges = {c: [] for c in candidats}
    for c1 in candidats:
        for c2, votes in matrix[c1].items():
            if votes > matrix[c2].get(c1, 0):
                edges[c1].append(c2)

    visited = set()
    rec_stack = set()

    def dfs(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in edges[node]:
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
        rec_stack.remove(node)
        return False

    for node in candidats:
        if node not in visited:
            if dfs(node):
                return True
    return False

print("Preferences du jury:")
for i, pref in enumerate(preferences_jury, 1):
    print(f"  Membre {i}: {' > '.join(pref)}")

scores_borda = borda_score(preferences_jury, projets)
gagnant_borda = max(scores_borda, key=scores_borda.get)

mat = condorcet_matrix(preferences_jury, projets)
n_votants = len(preferences_jury)

gagnant_condorcet = None
for p in projets:
    if all(mat[p].get(autre, 0) > n_votants // 2 for autre in projets if autre != p):
        gagnant_condorcet = p
        break

scores_copeland = {p: 0 for p in projets}
for p1 in projets:
    for p2 in projets:
        if p1 != p2:
            if mat[p1][p2] > mat[p2][p1]:
                scores_copeland[p1] += 1
            elif mat[p1][p2] < mat[p2][p1]:
                scores_copeland[p1] -= 1
gagnant_copeland = max(scores_copeland, key=scores_copeland.get)

cycle = detect_cycle(mat)

print("\nComparaison des methodes de vote:")
print(f"Borda: {gagnant_borda} (scores: {dict(sorted(scores_borda.items(), key=lambda x: -x[1]))})")
print(f"Condorcet: {gagnant_condorcet if gagnant_condorcet else 'Pas de gagnant (cycle detecte)'}")
print(f"Copeland: {gagnant_copeland} (scores: {dict(sorted(scores_copeland.items(), key=lambda x: -x[1]))})")
print(f"Cycle de Condorcet detecte: {cycle}")

print("\nMatrice des duels:")
print("         " + "  ".join(p[-1] for p in projets))
for p1 in projets:
    row = [str(mat[p1].get(p2, '-')).center(2) for p2 in projets]
    print(f"  {p1[-1]}      {' '.join(row)}")

